def get_platform_register_health(filename):
    if str(filename).startswith("COMPOSITE_VIEW:"):
        return {
            "exists": "READ-ONLY",
            "records": 0,
            "latest_timestamp": "",
            "columns": "Composite control tower. No separate CSV register.",
            "status": "COMPOSITE VIEW / READ-ONLY",
            "risk": "LOW"
        }

    try:
        df = load_csv(filename)
        if df is None:
            return {
                "exists": "UNKNOWN",
                "records": 0,
                "latest_timestamp": "",
                "columns": "",
                "status": "CHECK REQUIRED",
                "risk": "MEDIUM"
            }

        df = df.fillna("")
        records = len(df)
        latest_timestamp = ""

        if records > 0 and "timestamp" in df.columns:
            latest_timestamp = clean(df.tail(1).iloc[0].get("timestamp"))

        columns = ", ".join([str(c) for c in list(df.columns)[:8]])
        if len(df.columns) > 8:
            columns += " ..."

        if records > 0:
            status = "ACTIVE WITH RECORDS"
            risk = "LOW"
        else:
            status = "REGISTER READY / NO RECORDS YET"
            risk = "MEDIUM"

        return {
            "exists": "YES",
            "records": records,
            "latest_timestamp": latest_timestamp,
            "columns": columns,
            "status": status,
            "risk": risk
        }

    except Exception as e:
        return {
            "exists": "ERROR",
            "records": 0,
            "latest_timestamp": "",
            "columns": str(e),
            "status": "REGISTER ERROR",
            "risk": "HIGH"
        }


