    "coverage_score",
    "qa_red_count",
    "qa_yellow_count",
    "qa_green_count",
    "crosswalk_red_count",
    "crosswalk_yellow_count",
    "crosswalk_green_count",
    "executive_summary",
    "evidence_story",
    "risk_story",
    "auditor_talk_track",
    "closure_story",
    "final_readiness_statement",
    "primary_routes",
