def sterile_sb_require_dependencies():
    required = [
        "sterile_page_shell",
        "sterile_clean",
        "sterile_hash_text",
        "sterile_now",
        "sterile_write_register",
        "sterile_add_lineage",
    ]

    missing = [name for name in required if name not in globals()]
    if missing:
        raise RuntimeError("Sterile connector sandbox blueprint dependencies missing: " + ", ".join(missing))


def sterile_sb_safe(value):
    value = sterile_clean(value)
    if value.lower() in ["nan", "none", "null"]:
        return ""
    return value


def sterile_sb_make_id(prefix, *parts):
    raw = "|".join([str(part) for part in parts])
    return prefix + "-" + sterile_hash_text(raw)[:12].upper()


def sterile_sb_badge(status):
    status = sterile_sb_safe(status).upper()

    if status in ["GREEN", "READY", "LOW RISK"]:
        return '<span class="st-badge st-green">GREEN</span>'
    if status in ["YELLOW", "CONDITIONAL", "PROPOSED"]:
        return '<span class="st-badge st-yellow">YELLOW</span>'
    if status in ["RED", "BLOCKED", "HIGH RISK"]:
        return '<span class="st-badge st-red">RED</span>'

    return '<span class="st-badge st-gray">UNKNOWN</span>'


def sterile_sb_status_from_score(score):
    try:
        score = int(float(score))
    except Exception:
        score = 0

    if score >= 80:
        return "GREEN"
    if score >= 65:
        return "YELLOW"
    return "RED"


def sterile_sb_supporting_routes(system_key):
    return "; ".join([
        f"/sterile-compounding/connector-sandbox-blueprint/{system_key}",
        f"/sterile-compounding/data-contracts/{system_key}",
        f"/sterile-compounding/mock-ingestion-lab/{system_key}",
        f"/sterile-compounding/connector-approval-board/{system_key}",
        f"/sterile-compounding/nonprod-poc-plan/{system_key}",
        "/sterile-compounding/reviewer-attestation",
        "/sterile-compounding/decision-log",
    ])


def sterile_sb_add_control(rows, system_key, system_name, group, name, status, priority, requirement, evidence, risk, not_allowed, route):
    payload = {
        "control_id": sterile_sb_make_id("ST-SBCTRL", system_key, group, name),
        "system_key": system_key,
        "system_name": system_name,
        "control_group": group,
        "control_name": name,
        "control_status": status,
        "control_priority": priority,
        "control_requirement": requirement,
        "evidence_needed": evidence,
        "risk_if_missing": risk,
        "not_allowed_action": not_allowed,
        "supporting_route": route,
        "last_checked": sterile_now(),
    }

    payload["control_hash"] = sterile_hash_text(
        sterile_sb_json.dumps(payload, sort_keys=True)
    )

    rows.append(payload)


def sterile_sb_build_registers():
    sterile_sb_require_dependencies()

    blueprint_rows = []
    control_rows = []

    for system in STERILE_SANDBOX_SYSTEMS:
        system_key = sterile_sb_safe(system["system_key"])
        system_name = sterile_sb_safe(system["system_name"])
        score = int(system["score"])
        status = sterile_sb_status_from_score(score)

        payload = {
            "sandbox_id": sterile_sb_make_id("ST-SANDBOX", system_key),
            "system_key": system_key,
            "system_name": system_name,
            "sandbox_status": status,
            "sandbox_score": score,
            "recommended_sequence": system["sequence"],
            "sandbox_pattern": system["pattern"],
            "nonprod_data_rule": system["data_rule"],
            "allowed_inputs": system["allowed"],
            "not_allowed_inputs": system["not_allowed"],
            "credential_rule": system["credential"],
            "writeback_rule": system["writeback"],
            "source_of_truth_boundary": system["boundary"],
            "first_safe_test": system["test"],
            "minimum_controls": "No production data; no credentials; no writeback; no protected-route patch; owner approval before connector design; security/privacy review before any non-production API use.",
            "approval_required": system["approval"],
            "success_signal": system["success"],
            "supporting_routes": sterile_sb_supporting_routes(system_key),
            "last_checked": sterile_now(),
        }

        payload["sandbox_hash"] = sterile_hash_text(
            sterile_sb_json.dumps(payload, sort_keys=True)
        )

        blueprint_rows.append(payload)

        sterile_sb_add_control(
            control_rows,
            system_key,
            system_name,
            "01 Boundary",
            "Confirm non-production-only boundary",
            "GREEN",
            "P0",
            "Sandbox must remain mock, synthetic, or approved non-production only.",
            "Boundary statement and reviewed route bundle.",
            "Without this, stakeholders may mistake planning for production integration.",
            "No production API call, no production pull, no production writeback.",
            f"/sterile-compounding/connector-sandbox-blueprint/{system_key}",
        )

        sterile_sb_add_control(
            control_rows,
            system_key,
            system_name,
            "02 Data",
            "Confirm allowed input data",
            status,
            "P0",
            system["data_rule"],
            "Data contract, field mapping, and mock ingestion record.",
            "Unapproved data can create privacy, validation, and source-of-truth risk.",
            system["not_allowed"],
            f"/sterile-compounding/data-contracts/{system_key}",
        )

        sterile_sb_add_control(
            control_rows,
            system_key,
            system_name,
            "03 Credentials",
            "Confirm no credential use in blueprint phase",
            "GREEN",
            "P0",
            system["credential"],
            "Credential rule and security review note.",
            "Credential use before approval can create security exposure.",
            "No token, password, client secret, service principal, or connection string stored in app.py or CSV.",
            f"/sterile-compounding/connector-sandbox-blueprint/{system_key}",
        )

        sterile_sb_add_control(
            control_rows,
            system_key,
            system_name,
            "04 Writeback",
            "Confirm no writeback",
            "GREEN",
            "P0",
            system["writeback"],
            "No-writeback statement and source-of-truth boundary.",
            "Writeback can alter enterprise records or create validation impact.",
            "No create/update/delete operation against source systems.",
            f"/sterile-compounding/connector-sandbox-blueprint/{system_key}",
        )

        sterile_sb_add_control(
            control_rows,
            system_key,
            system_name,
            "05 Approval",
            "Confirm required approvals before POC",
            "YELLOW",
            "P1",
            system["approval"],
            "Reviewer attestation and decision log entry.",
            "POC may proceed without correct owner/security/QA awareness.",
            "No live connector design without named owner review.",
            "/sterile-compounding/reviewer-attestation",
        )

        sterile_sb_add_control(
            control_rows,
            system_key,
            system_name,
            "06 Evidence",
            "Confirm success signal and evidence route",
            status,
            "P1",
            system["success"],
            "POC evidence packet and sandbox blueprint row.",
            "POC success may be unclear or impossible to defend.",
            "No verbal-only evidence; every POC claim needs a route, register, or export.",
            "/sterile-compounding/poc-evidence-packet",
        )

    blueprint_df = sterile_sb_pd.DataFrame(blueprint_rows)
    blueprint_df = blueprint_df.reindex(columns=STERILE_CONNECTOR_SANDBOX_BLUEPRINT_COLUMNS).fillna("")

    control_df = sterile_sb_pd.DataFrame(control_rows)
    control_df = control_df.reindex(columns=STERILE_SANDBOX_CONTROL_CHECKLIST_COLUMNS).fillna("")

    sterile_write_register(
        STERILE_CONNECTOR_SANDBOX_BLUEPRINT_REGISTER,
        blueprint_df,
        STERILE_CONNECTOR_SANDBOX_BLUEPRINT_COLUMNS
    )

    sterile_write_register(
        STERILE_SANDBOX_CONTROL_CHECKLIST_REGISTER,
        control_df,
        STERILE_SANDBOX_CONTROL_CHECKLIST_COLUMNS
    )

    return blueprint_df, control_df


