@app.route("/sterile-compounding/connector-sandbox-blueprint/<system_key>")
def sterile_compounding_connector_sandbox_blueprint_detail(system_key):
    blueprint_df, control_df = sterile_sb_build_registers()
    system_key = sterile_sb_safe(system_key)

    match = blueprint_df[blueprint_df["system_key"].astype(str) == str(system_key)].copy() if not blueprint_df.empty else blueprint_df

    if match.empty:
        return sterile_sb_Response("Connector sandbox blueprint not found.", status=404)

    row = match.iloc[0].to_dict()
    controls = control_df[control_df["system_key"].astype(str) == str(system_key)].copy() if not control_df.empty else control_df

    detail_rows = ""

    for key in STERILE_CONNECTOR_SANDBOX_BLUEPRINT_COLUMNS:
        label = key.replace("_", " ").title()
        value = sterile_sb_safe(row.get(key, ""))

        if key == "sandbox_status":
            value = sterile_sb_badge(value)
        elif key == "sandbox_hash":
            value = f"<code>{value}</code>"
        elif key == "supporting_routes":
            routes = [r.strip() for r in value.split(";") if r.strip()]
            value = "<br>".join([f'<a href="{r}">{r}</a>' for r in routes])

