@app.after_request
def sterile_compounding_connector_sandbox_blueprint_dashboard_injection(response):
    try:
        if sterile_sb_request.path not in [
            "/sterile-compounding",
            "/sterile-compounding/enhancement-backlog",
            "/sterile-compounding/stakeholder-review-board",
            "/sterile-compounding/reviewer-attestation",
            "/sterile-compounding/decision-log",
            "/sterile-compounding/integration-blueprint",
            "/sterile-compounding/data-contracts",
            "/sterile-compounding/mock-ingestion-lab",
            "/sterile-compounding/connector-approval-board",
            "/sterile-compounding/nonprod-poc-plan",
        ]:
            return response

        if response.status_code != 200:
            return response

        content_type = response.headers.get("Content-Type", "")
        if "text/html" not in content_type:
            return response

        if getattr(response, "direct_passthrough", False):
            return response

        html = response.get_data(as_text=True)

        if not html or "sterile-connector-sandbox-blueprint-panel" in html:
            return response

        panel = """
        <section class="st-panel" id="sterile-connector-sandbox-blueprint-panel">
            <h2>Connector Sandbox Blueprint + Control Checklist</h2>
            <p class="st-note">
                Defines safe non-production connector sandbox patterns, no-credential rules, no-writeback boundaries,
                approval gates, and evidence controls before any future connector POC.
            </p>
            <div style="display:flex; flex-wrap:wrap; gap:10px; margin-top:12px;">
                <a class="st-button" href="/sterile-compounding/connector-sandbox-blueprint">Connector Sandbox Blueprint</a>
                <a class="st-button st-button-dark" href="/sterile-compounding/sandbox-control-checklist">Sandbox Control Checklist</a>
                <a class="st-button st-button-dark" href="/sterile-compounding/connector-sandbox-blueprint/export">Export Blueprint</a>
                <a class="st-button st-button-dark" href="/sterile-compounding/sandbox-control-checklist/export">Export Controls</a>
            </div>
        </section>
        """

        lower_html = html.lower()

        if "</body>" in lower_html:
            index = lower_html.rfind("</body>")
            updated_html = html[:index] + panel + html[index:]
        else:
            updated_html = html + panel

        response.set_data(updated_html)
        response.headers["Content-Length"] = str(len(response.get_data()))
        return response

    except Exception as exc:
        print(f"Sterile connector sandbox blueprint injection skipped safely: {exc}")
        return response


